function normalizarNumero(jid) {
  if (!jid) return '';
  return jid.replace(/@[\w.]+$/, '').trim();
}

const body = $input.first().json.body || $input.first().json;
const nomeInstancia = body.instance || '';
const remoteJid = body.data?.key?.remoteJid || '';
const fromMe = body.data?.key?.fromMe || false;
const eventType = body.event || body.data?.event || '';
const message_id = body.data?.key?.id || '';

// Descarta eventos de sistema
const EVENTOS_IGNORAR = ['MESSAGE_ACK', 'MESSAGES_UPDATE', 'PRESENCE_UPDATE', 'CALL'];
if (EVENTOS_IGNORAR.some(e => eventType.includes(e))) {
  throw new Error('EVENTO_IGNORADO: ' + eventType);
}

// Descarta mensagens próprias
if (fromMe) throw new Error('MENSAGEM_PROPRIA');

// Descarta mensagens sem ID (evita duplicatas de eventos sem identificador)
if (!message_id) throw new Error('MENSAGEM_SEM_ID');

// Descarta status e reações
const tipoMensagem = Object.keys(body.data?.message || {}).filter(k => k !== 'messageContextInfo')[0] || '';
const TIPOS_IGNORAR = ['reactionMessage', 'protocolMessage', 'senderKeyDistributionMessage', 'statusJidList'];
if (TIPOS_IGNORAR.includes(tipoMensagem)) {
  throw new Error('TIPO_IGNORADO: ' + tipoMensagem);
}

const mensagemTexto = (
  body.data?.message?.conversation ||
  body.data?.message?.extendedTextMessage?.text ||
  body.data?.message?.imageMessage?.caption ||
  body.data?.message?.documentMessage?.caption ||
  body.data?.message?.buttonsResponseMessage?.selectedDisplayText ||
  body.data?.message?.listResponseMessage?.title ||
  ''
).trim();

if (!mensagemTexto) throw new Error('MENSAGEM_VAZIA');

const unidade = UNIDADES[nomeInstancia];
if (!unidade) throw new Error('UNIDADE_NAO_ENCONTRADA: ' + nomeInstancia);

const numero_remetente = normalizarNumero(remoteJid);
const numero_receptor = normalizarNumero(body.data?.key?.participant || '') || unidade.numero_whatsapp;
const nome_whatsapp = body.data?.pushName || body.data?.key?.pushName || '';

return [{
  json: {
    numero_remetente,
    numero_receptor,
    mensagem: mensagemTexto,
    message_id,
    nome_whatsapp,
    timezone: unidade.timezone,
    ...unidade
  }
}];

