  .replaceAll('{{estagio_lead}}', dados.estagio_lead || 'NOVO');

const messages = dados.historico_mensagens || [{ role: 'user', content: dados.mensagem }];

const agora = new Date().toLocaleDateString('pt-BR', {
  timeZone: 'America/Cuiaba',
  weekday: 'long',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
});

systemPrompt = systemPrompt.replaceAll('{{data_atual}}', agora);

const diasNomes = ['domingo','segunda-feira','terça-feira','quarta-feira','quinta-feira','sexta-feira','sábado'];
const base = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Cuiaba' }));
let proximasDatas = '';
for (let i = 1; i <= 7; i++) {
  const d = new Date(base);
  d.setDate(base.getDate() + i);
  const dd = String(d.getDate()).padStart(2,'0');
  const mm = String(d.getMonth()+1).padStart(2,'0');
  const yyyy = d.getFullYear();
  proximasDatas += `${diasNomes[d.getDay()]}: ${dd}/${mm}/${yyyy}\n`;
}
systemPrompt = systemPrompt.replaceAll('{{proximas_datas}}', proximasDatas.trim());

return [{
  json: {
    ...dados,
    system_prompt_final: systemPrompt,
    messages_payload: messages
  }
}];

